      "domain": "gimp",
      "domainLabel": "GIMP",
      "platform": "Ubuntu",
      "category": "GUI Tasks",
      "sourcePath": "ubuntu/gimp/GIMP_GIMP_Manage_Layers_Masks_and_Blend_States",
      "imageCount": 13,
