      "platform": "Ubuntu",
      "category": "GUI Tasks",
      "sourcePath": "ubuntu/gimp/GIMP_GIMP_Transform_Image_Geometry_and_Canvas",
      "imageCount": 8,
      "stateCardCount": 3,
      "runtimeCardCount": 3,
      "planStepCount": 7,
